SELECT p.project_id, p.project_code, p.project_name, p.industry, p.region, p.region_id, p.short_name,
       p.established_year, p.project_category, p.project_dept, p.project_status, p.project_stage, p.acceptance_status,
       p.estimated_workload, ROUND(p.actual_workload / 8, 3) + COALESCE(p.adjust_workload, 0) AS actual_workload, p.adjust_workload, p.project_address, p.project_plan, p.project_description,
       p.project_manager_id, p.market_manager_id, p.participants, p.sales_manager_id, p.sales_contact,
       p.team_leader_id, p.customer_id, p.customer_contact_id, p.merchant_contact, p.merchant_phone,
       p.start_date, p.end_date, p.production_date, p.acceptance_date, p.project_budget, p.project_cost,
       p.expense_budget, p.cost_budget, p.labor_cost, p.purchase_cost, p.approval_status, p.approval_reason,
       p.industry_code, p.region_code, p.remark, p.tax_rate, p.confirm_user_id, p.confirm_time,
       p.reserved_field1, p.reserved_field2, p.reserved_field3, p.reserved_field4, p.reserved_field5,
       p.del_flag, p.create_by, p.create_time, p.update_by, p.update_time, p.revenue_confirm_status,
       p.revenue_confirm_year, p.revenue_confirm_date, p.confirm_amount, p.after_tax_amount, p.company_revenue_confirmed_by,
       p.company_revenue_confirmed_time,
       sr.region_name,
       ca.contract_amount, ca.contract_status, ca.contract_name, ca.contract_code,
       u_upd.nick_name AS update_by_name,
       u1.nick_name AS project_manager_name,
       tc.team_confirm_depts,
       tc.team_confirm_amount,
       p.parent_id, p.project_level, p.task_code,
       pp.project_name as parent_project_name
FROM pm_project p
LEFT JOIN pm_project pp ON p.parent_id = pp.project_id
LEFT JOIN pm_secondary_region sr ON p.region_id = sr.region_id
LEFT JOIN (
    SELECT pcr.project_id,
           SUM(c.contract_amount) AS contract_amount,
           MAX(c.contract_status) AS contract_status,
           GROUP_CONCAT(c.contract_name ORDER BY c.contract_id SEPARATOR '\n') AS contract_name,
           GROUP_CONCAT(c.contract_code ORDER BY c.contract_id SEPARATOR '\n') AS contract_code
    FROM pm_project_contract_rel pcr
    JOIN pm_contract c ON pcr.contract_id = c.contract_id AND c.del_flag = '0'
    WHERE pcr.del_flag = '0' AND pcr.rel_status = '有效'
    GROUP BY pcr.project_id
) ca ON p.project_id = ca.project_id
LEFT JOIN (
    SELECT t.project_id,
           GROUP_CONCAT(DISTINCT d.dept_name ORDER BY d.dept_name SEPARATOR '、') AS team_confirm_depts,
           SUM(t.confirm_amount) AS team_confirm_amount
    FROM pm_team_revenue_confirmation t
    JOIN sys_dept d ON t.dept_id = d.dept_id
    WHERE t.del_flag = '0'
    GROUP BY t.project_id
) tc ON p.project_id = tc.project_id
LEFT JOIN sys_user u_upd ON p.update_by COLLATE utf8mb4_unicode_ci = u_upd.user_name
LEFT JOIN sys_user u1 ON p.project_manager_id = u1.user_id
LEFT JOIN sys_dept d ON CAST(p.project_dept AS CHAR) COLLATE utf8mb4_unicode_ci = CAST(d.dept_id AS CHAR)
LEFT JOIN sys_user u_create ON p.create_by COLLATE utf8mb4_unicode_ci = u_create.user_name

